"""Data-driven renderer for the submission case-study page."""

from datetime import datetime
from html import escape


def _badge(text: str, class_name: str) -> str:
    return f'<span class="{class_name}">{escape(text)}</span>'


def generate_html_report(findings: list[dict], patterns: dict, verification: dict) -> str:
    records = [record for record in findings if record.get("buildability_verdict") != "UNKNOWN"]
    total = len(records)
    buildable = sum(record.get("buildability_verdict") == "YES" for record in records)
    self_serve = sum("Tier 1" in record.get("accessibility_tier", "") for record in records)
    refined = sum(record.get("refined_from_external_verification", False) for record in records)
    oauth = patterns.get("auth_analysis", {}).get("oauth2_percentage", 0)
    quick_wins = patterns.get("quick_wins", {})
    hard_problems = patterns.get("hard_problems", {})
    verification_records = verification.get("verified_apps", [])
    alignment = verification.get("accuracy_percentage", 0)
    evaluated = verification.get("field_checks_evaluated", 0)
    aligned = verification.get("field_checks_passed", 0)

    def tier_class(value: str) -> str:
        if "Tier 1" in value:
            return "tier1"
        if "Tier 2" in value:
            return "tier2"
        return "tier3"

    table_rows = []
    for index, record in enumerate(records):
        hidden = " dataset-extra" if index >= 30 else ""
        hidden_style = ' style="display:none"' if index >= 30 else ""
        auth = "".join(_badge(method, "method-badge") for method in record.get("auth_methods", [])) or "—"
        verdict = record.get("buildability_verdict", "UNKNOWN")
        verdict_class = "status-yes" if verdict == "YES" else "status-no" if verdict == "NO" else "status-unknown"
        evidence_url = record.get("evidence_url", "")
        evidence = f'<a href="{escape(evidence_url, quote=True)}" target="_blank" rel="noreferrer">Docs ↗</a>' if evidence_url.startswith("http") else "—"
        blocker = record.get("main_blocker", "None")
        table_rows.append(
            f'<tr class="filter-row{hidden}" data-buildable="{escape(verdict)}" data-tier="{escape(record.get("accessibility_tier", ""))}"{hidden_style}>'
            f'<td>{record.get("id", index + 1):02d}</td><td><strong>{escape(record.get("app_name", "Unknown"))}</strong></td>'
            f'<td>{auth}</td><td>{_badge(record.get("accessibility_tier", "Unknown").split(":")[0], tier_class(record.get("accessibility_tier", "")))}</td>'
            f'<td>{escape(record.get("api_surface", "Unknown"))}</td><td>{_badge(verdict.title(), verdict_class)}</td>'
            f'<td>{escape("—" if blocker == "None" else blocker)}</td><td>{evidence}</td></tr>'
        )

    review_rows = []
    field_names = {"auth_methods_verified": "Auth", "accessibility_tier_verified": "Access", "api_surface_verified": "API", "buildability_verdict_verified": "Buildability"}
    for record in verification_records[:10]:
        fields = " · ".join(label for key, label in field_names.items() if record.get(key) is not None) or "Overall review"
        status = record.get("overall_status", "Unverifiable")
        status_class = "status-yes" if status == "Correct" else "status-unknown" if status in {"Partial", "Unverifiable"} else "status-no"
        review_rows.append(
            f'<tr><td><strong>{escape(record.get("app_name", "Unknown"))}</strong></td><td>{escape(fields)}</td>'
            f'<td>{_badge("Aligned" if status == "Correct" else status, status_class)}</td>'
            f'<td>{escape(record.get("evidence_summary", "No review note recorded."))}</td></tr>'
        )

    quick_tags = "".join(f"<li>{escape(app)}</li>" for app in quick_wins.get("apps", [])[:15])
    hard_tags = "".join(f"<li>{escape(app)}</li>" for app in hard_problems.get("apps", [])[:12])
    enterprise = [record["app_name"] for record in records if "Tier 3" in record.get("accessibility_tier", "")]
    approvals = [record["app_name"] for record in records if "Tier 2" in record.get("accessibility_tier", "")]
    api_limited = [record["app_name"] for record in records if "API" in record.get("main_blocker", "")]

    return f'''<!DOCTYPE html>
<html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>SaaS Integration Research — Product Ops Case Study</title>
<style>
:root{{--navy:#0f1b2d;--slate:#3d5066;--muted:#63768c;--line:#e2e8ef;--bg:#f7f9fb;--blue:#2f5fd8;--green:#1f7a52;--amber:#9a6b1f;--red:#a13a34;--radius:8px}}*{{box-sizing:border-box}}html{{scroll-behavior:smooth}}body{{margin:0;background:var(--bg);color:var(--slate);font:15.5px/1.6 Inter,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif}}.container{{max-width:1140px;margin:32px auto;background:#fff;border:1px solid var(--line);border-radius:12px;overflow:hidden;box-shadow:0 2px 14px -6px rgba(15,27,45,.12)}}header{{background:var(--navy);color:#fff;padding:56px 60px 48px;border-bottom:4px solid var(--blue)}}.eyebrow,.section-label{{font-size:.72rem;font-weight:700;letter-spacing:.1em;text-transform:uppercase}}.eyebrow{{color:#a9c0f5;margin:0 0 18px}}header h1{{font-size:clamp(1.8rem,3.2vw,2.5rem);line-height:1.2;margin:0 0 16px;max-width:820px}}.lede{{color:rgba(255,255,255,.75);max-width:720px;margin:0}}.meta{{display:flex;flex-wrap:wrap;gap:28px;margin-top:28px;padding-top:22px;border-top:1px solid rgba(255,255,255,.12)}}.meta .item{{display:flex;flex-direction:column}}.meta .k{{color:rgba(255,255,255,.5);font-size:.68rem;letter-spacing:.08em;text-transform:uppercase}}.meta .v{{color:#fff;font-weight:700}}section{{padding:48px 60px;border-bottom:1px solid var(--line)}}.section-label{{color:var(--blue);margin-bottom:10px}}h2{{margin:0 0 8px;color:var(--navy);font-size:1.5rem;line-height:1.3}}h3{{color:var(--navy);font-size:1.02rem;margin:30px 0 12px}}.section-sub{{margin:0 0 28px;color:var(--muted);max-width:760px}}.stats-grid{{display:grid;grid-template-columns:repeat(4,1fr);gap:1px;background:var(--line);border:1px solid var(--line);border-radius:var(--radius);overflow:hidden}}.stat-card{{background:#fff;padding:24px 22px}}.num{{font-size:2.1rem;font-weight:800;color:var(--navy);line-height:1}}.num.accent,.stat.accent{{color:var(--blue)}}.frac{{font-size:1rem;color:#8397ac;font-weight:500}}.label{{font-weight:700;color:var(--navy);margin-top:7px}}.sub,.pattern-card p{{font-size:.84rem;color:var(--muted);margin:5px 0 0}}.callout{{display:flex;gap:12px;margin-top:32px;padding:18px 22px;background:#fbf6ec;border:1px solid #ecd9b3;border-left:3px solid var(--amber);border-radius:var(--radius)}}.callout .icon{{width:20px;height:20px;flex:none;border-radius:50%;background:var(--amber);color:#fff;text-align:center;font-weight:700;font-size:.75rem;line-height:20px}}.callout strong{{color:var(--amber);font-size:.78rem;letter-spacing:.04em;text-transform:uppercase}}.callout p{{margin:4px 0 0;color:var(--navy);font-size:.92rem}}.pattern-grid{{display:grid;grid-template-columns:repeat(4,1fr);gap:16px}}.pattern-card,.matrix-card,.info-block,.verification-card,.recs,.loop-list{{background:#fff;border:1px solid var(--line);border-radius:var(--radius)}}.pattern-card{{padding:22px}}.pattern-card h4,.info-block h4{{font-size:.74rem;text-transform:uppercase;letter-spacing:.06em;color:var(--muted);margin:0 0 12px}}.stat{{font-size:1.9rem;font-weight:800;color:var(--navy);line-height:1}}.stat-label{{font-weight:700;color:var(--navy);margin-top:6px}}.filter-group{{display:flex;gap:8px;margin-bottom:18px;flex-wrap:wrap}}.filter-btn{{background:#fff;border:1px solid var(--line);padding:7px 15px;border-radius:6px;font:600 .82rem inherit;color:var(--slate);cursor:pointer}}.filter-btn.active{{background:var(--navy);border-color:var(--navy);color:#fff}}.table-wrap{{overflow:auto;border:1px solid var(--line);border-radius:var(--radius)}}table{{width:100%;border-collapse:collapse;font-size:.87rem;min-width:820px}}th{{background:#f7f9fb;color:var(--muted);font-size:.7rem;text-transform:uppercase;letter-spacing:.06em;text-align:left;padding:12px 15px}}td{{padding:12px 15px;border-top:1px solid #eef2f6;vertical-align:middle}}td:first-child{{color:#8397ac;font-family:monospace}}td strong{{color:var(--navy)}}tbody tr:hover{{background:#f7f9fb}}a{{color:var(--blue);font-weight:700;text-decoration:none}}.method-badge,.tier1,.tier2,.tier3,.status-yes,.status-no,.status-unknown{{display:inline-block;padding:3px 8px;border-radius:4px;font-size:.7rem;font-weight:700;margin:1px 3px 1px 0}}.method-badge{{background:#f7f9fb;border:1px solid var(--line);color:var(--slate);font-family:monospace;font-weight:500}}.tier1,.status-yes{{background:#eaf6f0;color:var(--green)}}.tier2,.status-unknown{{background:#fbf6ec;color:var(--amber)}}.tier3,.status-no{{background:#fbeeed;color:var(--red)}}.table-footer{{text-align:center;color:var(--muted);font-size:.84rem;margin:14px 0 0}}#datasetToggle{{color:var(--blue);background:none;border:0;border-bottom:1px solid var(--blue);font:700 inherit;cursor:pointer;margin-left:8px}}.matrix{{display:grid;grid-template-columns:1fr 1fr;gap:16px}}.matrix-card{{padding:24px}}.matrix-card.wins{{border-top:3px solid var(--green)}}.matrix-card.hard{{border-top:3px solid var(--red)}}.matrix-card h4{{font-size:.75rem;text-transform:uppercase;letter-spacing:.06em;color:var(--muted);margin:0 0 10px}}.matrix-card .headline{{font-weight:700;font-size:1.15rem;color:var(--navy)}}.matrix-card ul{{padding:0;list-style:none;display:flex;flex-wrap:wrap;gap:6px}}.matrix-card li{{background:#f7f9fb;border:1px solid var(--line);border-radius:5px;padding:5px 11px;font-size:.83rem;color:var(--navy)}}.footnote{{margin-top:18px;padding-top:14px;border-top:1px solid #eef2f6;font-weight:700;font-size:.84rem}}.wins .footnote{{color:var(--green)}}.hard .footnote{{color:var(--red)}}.info-block{{padding:22px 24px;margin-bottom:16px;border-left:3px solid var(--blue)}}.info-block.slate{{border-left-color:#8397ac}}.info-block ul{{list-style:none;padding:0;margin:0}}.info-block li{{padding:8px 0;border-top:1px solid #eef2f6;font-size:.9rem}}.loop-list,.recs{{padding:20px 24px}}.loop-item,.rec-item{{display:flex;gap:16px;padding:12px 0;border-top:1px solid #eef2f6}}.loop-item:first-child,.rec-item:first-child{{border-top:0}}.step,.rec-phase{{width:110px;flex:none;color:var(--blue);font:700 .72rem monospace;text-transform:uppercase}}.verification-card{{padding:28px}}.verification-header{{display:flex;justify-content:space-between;gap:24px;align-items:end}}.accuracy-big{{font-size:2.4rem;font-weight:800;color:var(--blue)}}.accuracy-big span{{font-size:.9rem;color:var(--muted)}}.accuracy-bar{{height:7px;background:#eef2f6;border-radius:4px;overflow:hidden;margin:18px 0}}.accuracy-fill{{height:100%;background:var(--blue)}}.verification-facts{{display:grid;grid-template-columns:repeat(6,1fr);gap:12px;border-top:1px solid #eef2f6;padding-top:18px}}.fact .k{{font-size:.68rem;color:var(--muted);text-transform:uppercase;font-weight:700}}.fact .v{{font-weight:700;color:var(--navy)}}code{{font:inherit;background:#f7f9fb;border:1px solid var(--line);padding:1px 5px;border-radius:3px}}footer{{background:var(--navy);padding:36px 60px;color:rgba(255,255,255,.7);font-size:.85rem}}footer p{{margin:0 0 6px}}footer strong{{color:#fff}}.meta-line{{font:normal .75rem monospace;color:rgba(255,255,255,.45);margin-top:12px;padding-top:12px;border-top:1px solid rgba(255,255,255,.08)}}@media(max-width:820px){{.container{{margin:0;border:0;border-radius:0}}header,section,footer{{padding:36px 20px}}.stats-grid{{grid-template-columns:repeat(2,1fr)}}.pattern-grid,.matrix{{grid-template-columns:1fr}}.verification-facts{{grid-template-columns:repeat(2,1fr)}}.loop-item,.rec-item,.verification-header{{flex-direction:column;align-items:start}}}}
</style></head><body><div class="container">
<header><p class="eyebrow">Product Operations · Take-Home Case Study</p><h1>Which SaaS apps are ready for agent integration?</h1><p class="lede">A scoped research pass across {total} SaaS APIs, mapping authentication, developer access, API surface, and buildability — with an evidence-grounded refinement loop.</p><div class="meta"><div class="item"><span class="k">Apps researched</span><span class="v">{total}</span></div><div class="item"><span class="k">Records reviewed</span><span class="v">{len(verification_records)} / {total}</span></div><div class="item"><span class="k">Field alignment</span><span class="v">{alignment:.1f}%</span></div><div class="item"><span class="k">Verification method</span><span class="v">ChatGPT-assisted, evidence-cited</span></div></div></header>
<section><div class="section-label">01 — Executive Summary</div><h2>The clearest signals from the completed research subset</h2><p class="section-sub">How many apps can ship today, how many are self-serve, which auth standard dominates, and what the verification loop changed.</p><div class="stats-grid"><div class="stat-card"><div class="num accent">{buildable}<span class="frac"> / {total}</span></div><div class="label">Buildable today</div><div class="sub">Public APIs suitable for agent toolkits.</div></div><div class="stat-card"><div class="num">{self_serve}<span class="frac"> / {total}</span></div><div class="label">Tier 1 self-serve</div><div class="sub">Credentials without a sales call.</div></div><div class="stat-card"><div class="num accent">{oauth:.0f}<span class="frac">%</span></div><div class="label">Use OAuth2</div><div class="sub">The dominant auth standard.</div></div><div class="stat-card"><div class="num">{quick_wins.get('count', 0)}</div><div class="label">Quick wins</div><div class="sub">Self-serve and buildable.</div></div></div><div class="callout"><span class="icon">!</span><div><strong>Scope note</strong><p>This report covers <b>{total} of the original 100 assigned apps</b>. IDs 51–100 are excluded rather than padded with placeholders. All {len(verification_records)} completed records were reviewed through a manually run ChatGPT workflow with cited official documentation. Field alignment is not a ground-truth claim.</p></div></div></section>
<section><div class="section-label">02 — Patterns & Headline Findings</div><h2>What repeats across the dataset</h2><p class="section-sub">Cross-cutting patterns in authentication, access, and buildability used to prioritize toolkit work.</p><div class="pattern-grid"><div class="pattern-card"><h4>Authentication landscape</h4><div class="stat accent">{oauth:.0f}%</div><div class="stat-label">Apps using OAuth2</div><p>Prioritize OAuth flows first, with API-key fallbacks where offered.</p></div><div class="pattern-card"><h4>Developer access</h4><div class="stat">{self_serve} / {total}</div><div class="stat-label">Fully self-serve</div><p>The remaining apps need approval, an enterprise relationship, or a more mature API.</p></div><div class="pattern-card"><h4>Buildability index</h4><div class="stat accent">{buildable / total * 100:.0f}%</div><div class="stat-label">Ready today</div><p>Business access constraints are a more common blocker than technical feasibility.</p></div><div class="pattern-card"><h4>Quick wins</h4><div class="stat">{quick_wins.get('count', 0)}</div><div class="stat-label">Immediate candidates</div><p>Highest ROI integrations with the least partnership friction.</p></div></div></section>
<section><div class="section-label">03 — App Findings Matrix</div><h2>Every completed record, one row at a time</h2><p class="section-sub">Filter by buildability or self-serve access. Each row retains its official documentation source.</p><div class="filter-group"><button class="filter-btn active" onclick="filterTable('all',event)">All apps</button><button class="filter-btn" onclick="filterTable('buildable',event)">Buildable only</button><button class="filter-btn" onclick="filterTable('self-serve',event)">Self-serve only</button></div><div class="table-wrap"><table><thead><tr><th>#</th><th>App</th><th>Auth</th><th>Access</th><th>API surface</th><th>Buildable</th><th>Blocker</th><th>Evidence</th></tr></thead><tbody>{''.join(table_rows)}</tbody></table></div><p class="table-footer"><span id="datasetStatus">Showing first 30 of {total} apps.</span><button id="datasetToggle" onclick="toggleFullDataset()">View full dataset →</button></p></section>
<section><div class="section-label">04 — Quick Wins vs. Hard Problems</div><h2>Where to invest, and where to negotiate</h2><p class="section-sub">Separate the apps a toolkit can ship now from the ones that need an access strategy.</p><div class="matrix"><div class="matrix-card wins"><h4>Quick wins · {quick_wins.get('count', 0)} apps</h4><div class="headline">Immediate toolkit candidates</div><p>Self-serve and buildable. Start here for the fastest time-to-market.</p><ul>{quick_tags}</ul><div class="footnote">→ {quick_wins.get('count', 0)} apps, low friction to ship</div></div><div class="matrix-card hard"><h4>Hard problems · {hard_problems.get('count', 0)} apps</h4><div class="headline">Partnership outreach required</div><p>Enterprise-gated or heavily restricted. Longer cycle, potentially high value.</p><ul>{hard_tags}</ul><div class="footnote">→ {hard_problems.get('count', 0)} apps need outreach</div></div></div></section>
<section><div class="section-label">05 — Research Workflow & Refinement Loop</div><h2>How the dataset was built</h2><p class="section-sub">An agent-driven first pass was checked through a separate ChatGPT review loop with explicit citations and structured outputs.</p><div class="info-block"><h4>Agent pipeline</h4><ul><li><strong>Research:</strong> {total} app records processed using Composio search context and GPT-4o structured output.</li><li><strong>Extraction:</strong> Auth, access tier, API surface, verdict, blocker, and evidence URL captured in a fixed schema.</li><li><strong>Controls:</strong> Checkpoints and validation rules prevent failed requests from becoming false negative findings.</li></ul></div><div class="info-block slate"><h4>Verification design</h4><ul><li><strong>Evidence review:</strong> ChatGPT compared every completed record against cited official documentation.</li><li><strong>Structured import:</strong> Results were required to provide field-level pass/fail/partial status and source URLs.</li><li><strong>Refinement:</strong> {refined} records were updated only where the external review proposed an explicit correction.</li></ul></div><h3>Feedback loop</h3><div class="loop-list"><div class="loop-item"><div class="step">Pass 1 · Agent</div><div><strong>Raw research</strong> on {total} apps using structured parsing.</div></div><div class="loop-item"><div class="step">Pass 2 · Review</div><div><strong>ChatGPT-assisted review</strong> against official documentation with citations.</div></div><div class="loop-item"><div class="step">Pass 3 · Refine</div><div><strong>{refined} record corrections applied</strong> from the review output.</div></div></div></section>
<section><div class="section-label">06 — Evidence-Grounded Verification</div><h2>Where the dataset agrees with cited sources</h2><p class="section-sub">Alignment is calculated only where the review returned explicit pass/fail outcomes. Partial and unverifiable results are not counted as agreement.</p><div class="verification-card"><div class="verification-header"><div><h3 style="margin:0">Field alignment across reviewed records</h3><p>External LLM-assisted review, not independent human verification or a ground-truth claim.</p></div><div class="accuracy-big">{alignment:.1f}%<span>field alignment</span></div></div><div class="accuracy-bar"><div class="accuracy-fill" style="width:{alignment}%"></div></div><div class="verification-facts"><div class="fact"><div class="k">Records reviewed</div><div class="v">{len(verification_records)} / {total}</div></div><div class="fact"><div class="k">Checks evaluated</div><div class="v">{evaluated}</div></div><div class="fact"><div class="k">Aligned</div><div class="v">{aligned} / {evaluated}</div></div><div class="fact"><div class="k">Refined</div><div class="v">{refined}</div></div><div class="fact"><div class="k">Cited records</div><div class="v">{verification.get('evidence_retrieved_count', 0)}</div></div><div class="fact"><div class="k">Confidence</div><div class="v">{escape(verification.get('confidence_level', 'Medium'))}</div></div></div></div><h3>Reviewed examples</h3><div class="table-wrap"><table><thead><tr><th>App</th><th>Fields tested</th><th>Result</th><th>Review note</th></tr></thead><tbody>{''.join(review_rows)}</tbody></table></div></section>
<section><div class="section-label">07 — Blockers & Recommendations</div><h2>What stands between the toolkit and the tail</h2><p class="section-sub">Access strategy matters most for the remaining apps.</p><div class="pattern-grid"><div class="pattern-card"><h4>Enterprise gated</h4><div class="stat">{len(enterprise)}</div><div class="stat-label">Apps affected</div><p>{escape(', '.join(enterprise) or 'None')}</p></div><div class="pattern-card"><h4>Approval required</h4><div class="stat">{len(approvals)}</div><div class="stat-label">Apps affected</div><p>Production access needs an approval, app review, or business account.</p></div><div class="pattern-card"><h4>API limitations</h4><div class="stat">{len(api_limited)}</div><div class="stat-label">Apps affected</div><p>Documented, but narrow or immature for the agent use case.</p></div><div class="pattern-card"><h4>Action</h4><div class="stat">OAuth2</div><div class="stat-label">Build priority</div><p>Start with OAuth2-first quick wins; pursue enterprise access in parallel.</p></div></div><h3>Strategic recommendations</h3><div class="recs"><div class="rec-item"><div class="rec-phase">Phase 1</div><div><strong>Build the {quick_wins.get('count', 0)} quick-win toolkits.</strong> Highest ROI and least friction.</div></div><div class="rec-item"><div class="rec-phase">Phase 2</div><div><strong>Open partnership conversations with {len(enterprise)} enterprise-gated apps.</strong> Treat them as a longer-term pipeline.</div></div><div class="rec-item"><div class="rec-phase">Continuous</div><div><strong>Monitor approval-gated APIs.</strong> Apply for access when product priorities justify the effort.</div></div></div></section>
<section><div class="section-label">08 — Evidence, Reproducibility & Limitations</div><h2>What's transparent, and what isn't</h2><p class="section-sub">A cited URL is a research source, not proof that every extracted field has been independently verified.</p><div class="info-block"><h4>Data pipeline transparency</h4><ul><li><strong>Agent code:</strong> <code>main.py</code> — Composio-assisted research orchestration.</li><li><strong>Verification workflow:</strong> <code>EXTERNAL_VERIFICATION_PROMPT.md</code> + <code>import_external_verification.py</code>.</li><li><strong>Pattern analysis:</strong> <code>analyze_patterns.py</code> — aggregation and clustering.</li><li><strong>Raw output:</strong> <code>final_findings.json</code> — {total} completed records.</li></ul></div><div class="callout"><span class="icon">i</span><div><strong>Known limitations</strong><p>Records 51–100 were not completed within the research window. Verification is ChatGPT-assisted rather than independent human review.</p></div></div></section>
<footer><p><strong>Product Ops Take-Home — Agent-Driven Research with Evidence-Aware Verification</strong></p><p class="meta-line">{total} apps researched · {len(verification_records)} reviewed · {evaluated} field checks · {aligned} aligned · {alignment:.1f}% field alignment · {refined} records refined</p></footer></div>
<script>function toggleFullDataset(){{const e=document.querySelectorAll('.dataset-extra'),t=document.getElementById('datasetToggle'),s=document.getElementById('datasetStatus'),x=t.dataset.expanded==='true';e.forEach(r=>r.style.display=x?'none':'');t.dataset.expanded=String(!x);t.textContent=x?'View full dataset →':'Show fewer rows';s.textContent=x?'Showing first 30 of {total} apps.':'Showing all {total} apps.'}}function filterTable(f,e){{const r=document.querySelectorAll('.filter-row'),b=document.querySelectorAll('.filter-btn'),x=document.getElementById('datasetToggle').dataset.expanded==='true';b.forEach(q=>q.classList.remove('active'));if(e)e.target.classList.add('active');r.forEach(q=>{{const m=f==='buildable'?q.dataset.buildable==='YES':f==='self-serve'?q.dataset.tier.includes('Tier 1'):true;q.style.display=((!q.classList.contains('dataset-extra')||x)&&m)?'':'none'}})}}</script></body></html>'''
